  // Sub-services translation keys
  d['id']['af.challenges_p_1']='Ketidakmampuan memproyeksikan dan mengelola arus kas secara efektif mengancam stabilitas operasional dan potensi pertumbuhan.';
  d['id']['af.challenges_h3_2']='Ketidakpastian Arus Kas';
  d['id']['af.challenges_p_3']='Investor dan pihak pengakuisisi membutuhkan laporan keuangan yang bersih dan dapat diaudit. Catatan yang tidak andal mengikis kepercayaan dan mengurangi valuasi.';
  d['id']['af.challenges_h3_4']='Kesulitan Menarik Investasi';
  d['id']['af.challenges_p_5']='Alur kerja pembukuan yang manual dan terfragmentasi memakan sumber daya berharga dan meningkatkan risiko kesalahan.';
  d['id']['af.challenges_h3_6']='Proses Pembukuan yang Tidak Efisien';
  d['id']['af.challenges_p_7']='Tanpa dasbor keuangan dan analitik real-time, tim kepemimpinan beroperasi tanpa arah terhadap indikator kinerja penting.';
  d['id']['af.challenges_h3_8']='Kurangnya Visibilitas Keuangan';
  d['id']['af.challenges_p_9']='Menavigasi standar PSAK/IFRS, peraturan perpajakan, dan persyaratan kepatuhan yang terus berkembang membutuhkan keahlian khusus.';
  d['id']['af.challenges_h3_10']='Kepatuhan Regulasi yang Kompleks';
  d['id']['af.challenges_p_11']='Kualitas data yang buruk menyebabkan keputusan bisnis yang cacat, hilangnya peluang, dan meningkatnya risiko kepatuhan.';
  d['id']['af.challenges_h3_12']='Data Keuangan Tidak Akurat';
  d['id']['af.core-services_p_1']='Merampingkan alur kerja keuangan, menerapkan otomatisasi, dan merancang proses terukur yang mengurangi biaya serta meningkatkan akurasi.';
  d['id']['af.core-services_h3_2']='Optimalisasi Proses Keuangan';
  d['id']['af.core-services_p_3']='Mengevaluasi dan memperkuat pengawasan internal, mengidentifikasi celah proses, dan memastikan kerangka tata kelola memenuhi harapan regulasi.';
  d['id']['af.core-services_h3_4']='Audit & Pengawasan Internal';
  d['id']['af.core-services_p_5']='Dasbor khusus, pelacakan KPI, dan laporan manajemen yang memberikan wawasan terukur untuk pengambilan keputusan yang tepat.';
  d['id']['af.core-services_h3_6']='Laporan Manajemen & Analitik';
  d['id']['af.core-services_p_7']='Kepemimpinan keuangan strategis untuk organisasi yang membutuhkan panduan tingkat eksekutif tanpa komitmen CFO penuh waktu.';
  d['id']['af.core-services_h3_8']='Layanan Penasihat CFO';
  d['id']['af.core-services_p_9']='Pembukuan ujung-ke-ujung, manajemen utang/piutang, dan pemrosesan penggajian dengan akurasi dan efisiensi.';
  d['id']['af.core-services_h3_10']='Manajemen Pembukuan & Penggajian';
  d['id']['af.core-services_p_11']='Menyiapkan laporan keuangan akurat yang sesuai dengan standar SAK/PSAK dan IFRS. Memeriksa laporan regulasi agar tepat waktu dan bebas kesalahan.';
  d['id']['af.core-services_h3_12']='Pelaporan Keuangan & Kepatuhan';
