  d['id']['bt.solution_label']='Pendekatan Kami';
  d['id']['bt.solution_title']='Keahlian Strategis dari Valuasi hingga Pasca-Penutupan';
  d['id']['bt.solution_desc']='Praktik transfer bisnis kami menghadirkan keahlian keuangan yang mendalam, pengetahuan pasar, dan pengalaman transaksi yang terbukti. Kami mengelola setiap aspek mulai dari valuasi awal hingga integrasi pasca-penutupan, memastikan hasil yang sukses bagi semua pihak.';
  d['id']['bt.core_1_title']='Valuasi Bisnis & Opini Kewajaran';
  d['id']['bt.core_1_desc']='Analisis valuasi komprehensif menggunakan DCF, kelipatan pasar, dan metode transaksi terdahulu untuk menetapkan nilai perusahaan yang defensibel.';
  d['id']['bt.core_2_title']='Advisory Sisi Pembeli (Buy-Side)';
  d['id']['bt.core_2_desc']='Identifikasi target, penyaringan, dan evaluasi bagi pengakuisisi yang mencari pertumbuhan strategis melalui peluang akuisisi.';
  d['id']['bt.core_3_title']='Advisory Sisi Penjual (Sell-Side)';
  d['id']['bt.core_3_desc']='Memaksimalkan nilai pemilik melalui proses penjualan yang kompetitif, penjangkauan pembeli, dan strategi negosiasi untuk hasil keluar yang optimal.';
  d['id']['bt.core_4_title']='Manajemen Uji Tuntas (Due Diligence)';
  d['id']['bt.core_4_desc']='Mengoordinasikan uji tuntas keuangan, hukum, komersial, dan operasional yang komprehensif di seluruh pemangku kepentingan transaksi.';
  d['id']['bt.core_5_title']='Struktur Deal & Negosiasi';
  d['id']['bt.core_5_desc']='Mengoptimalkan persyaratan transaksi, struktur imbalan, dan kerangka kontrak untuk melindungi kepentingan klien.';
  d['id']['bt.core_6_title']='Dukungan Integrasi Pasca-Merger';
  d['id']['bt.core_6_desc']='Memandu penyelarasan organisasi, integrasi operasional, dan harmonisasi budaya untuk mewujudkan sinergi kesepakatan.';
  d['id']['bu.workflow_label']='Proses Kami';
  d['id']['bu.workflow_title']='Alur Kerja Transaksi Terbukti';
  d['id']['bu.workflow_desc']='Proses terstruktur dan transparan yang memberikan hasil transisi bisnis yang sukses.';
