  d['id']['rm.challenges_label']='Tantangan Bisnis';
  d['id']['rm.challenges_title']='Risiko yang Anda Hadapi Saat Ini';
  d['id']['rm.challenges_desc']='Bisnis modern menavigasi lanskap risiko yang semakin kompleks. Tanpa pendekatan proaktif, tantangan-tantangan ini dapat mengikis nilai, mengekspos organisasi Anda pada sanksi regulasi, dan merusak kepercayaan pemangku kepentingan.';
  d['id']['rm.challenge_1_title']='Visibilitas Risiko yang Tidak Lengkap';
  d['id']['rm.challenge_1_desc']='Titik buta (blind spots) dalam identifikasi risiko membuat organisasi rentan terhadap ancaman yang tidak terduga.';
  d['id']['rm.challenge_2_title']='Pengendalian Internal yang Lemah';
  d['id']['rm.challenge_2_desc']='Lingkungan pengendalian yang tidak memadai memungkinkan kesalahan, ketidakefisienan, dan penipuan (fraud) terus terjadi tanpa terdeteksi.';
  d['id']['rm.challenge_3_title']='Kesenjangan Kepatuhan Regulasi';
  d['id']['rm.challenge_3_desc']='Peraturan yang terus berkembang menuntut pemantauan dan adaptasi terus-menerus untuk tetap patuh.';
  d['id']['rm.challenge_4_title']='Tata Kelola yang Tidak Memadai';
  d['id']['rm.challenge_4_desc']='Struktur tata kelola yang lemah membahayakan kualitas pengambilan keputusan dan akuntabilitas.';
  d['id']['rm.challenge_5_title']='Tidak Ada Pendekatan Kelangsungan Bisnis';
  d['id']['rm.challenge_5_desc']='Tanpa perencanaan kelangsungan bisnis (business continuity), gangguan operasional dapat merembet menjadi kegagalan berkepanjangan.';
  d['id']['rm.services_label']='Apa yang Kami Lakukan';
  d['id']['rm.services_title']='Layanan Utama Manajemen Risiko';
  d['id']['rm.services_desc']='Solusi penasihat risiko komprehensif yang dirancang untuk memperkuat ketahanan dan struktur tata kelola organisasi Anda.';
  d['id']['rm.service_1_title']='Penilaian & Pemetaan Risiko Perusahaan';
  d['id']['rm.service_1_desc']='Identifikasi, analisis, dan prioritas risiko yang sistematis di seluruh organisasi Anda dengan peta panas (heatmaps) risiko dan register risiko komprehensif.';
  d['id']['rm.service_2_title']='Desain & Pengujian Pengendalian Internal';
  d['id']['rm.service_2_desc']='Desain, implementasi, dan pengujian mekanisme pengendalian internal untuk melindungi aset, memastikan akurasi, dan meningkatkan efisiensi operasional.';
  d['id']['rm.service_3_title']='Investigasi Fraud & Analisis Forensik';
  d['id']['rm.service_3_desc']='Investigasi forensik menyeluruh terhadap dugaan fraud, pelanggaran keuangan, dan ketidakberesan dengan temuan berbasis bukti yang dapat ditindaklanjuti.';
  d['id']['rm.service_4_title']='Pengembangan Kerangka Tata Kelola';
  d['id']['rm.service_4_desc']='Desain dan implementasi struktur tata kelola, piagam (charters), dan kebijakan yang menetapkan akuntabilitas dan pengawasan strategis yang jelas.';
  d['id']['rm.service_5_title']='Advisory & Pemantauan Kepatuhan';
  d['id']['rm.service_5_desc']='Program kepatuhan ujung-ke-ujung yang mencakup analisis kesenjangan regulasi, pemantauan, pelaporan, dan perencanaan tindakan perbaikan.';
  d['id']['rm.service_6_title']='Perencanaan Kelangsungan Bisnis';
  d['id']['rm.service_6_desc']='Pengembangan dan pengujian rencana kelangsungan bisnis (BCP) dan pemulihan bencana (DRP) untuk memastikan ketahanan operasional selama gangguan.';
  d['id']['rm.cta_title']='Siap Memperkuat Pemosisian Risiko Anda?';
  d['id']['rm.cta_desc']='Tim kami siap membantu Anda menavigasi tantangan risiko yang kompleks dan membangun ketahanan organisasi yang berkelanjutan.';
  d['id']['rm.cta_button']='Hubungi Kami';
  d['id']['rm.cta_call']='Telepon Kami';
  d['id']['rm.deliverables_label']='Hasil Serahan';
  d['id']['rm.deliverables_title']='Apa yang Anda Terima';
  d['id']['rm.deliverables_desc']='Setiap keterlibatan menghasilkan output nyata dan dapat ditindaklanjuti yang dirancang untuk memperkuat risiko Anda dan menginformasikan pengambilan keputusan strategis.';
