  d['id']['rm.experts_desc']='Advisors profesional dengan keahlian mendalam dalam risiko perusahaan, tata kelola, dan kepatuhan.';
  d['id']['rm.expert_1_name']='Adine K. Nadya';
  d['id']['rm.expert_1_role']='Mitra, Manajemen Risiko';
  d['id']['rm.expert_2_name']='Andi Rio Ilhad Monry';
  d['id']['rm.expert_2_role']='Managing Partner';
  d['id']['rm.faq_label']='Pertanyaan';
  d['id']['rm.faq_title']='Pertanyaan yang Sering Diajukan';
  d['id']['rm.faq_1_q']='Apa itu manajemen risiko perusahaan dan mengapa bisnis saya membutuhkannya?';
  d['id']['rm.faq_1_a']='Enterprise risk management (ERM) adalah pendekatan terstruktur untuk mengidentifikasi, menilai, dan merespons risiko yang dapat memengaruhi tujuan organisasi Anda. Praktik kami merancang kerangka kerja praktis yang melindungi bisnis Anda sekaligus memungkinkan pertumbuhan yang percaya diri dan terinformasi.';
  d['id']['rm.faq_2_q']='Bagaimana pendekatan Chatura terhadap desain dan pengujian pengendalian internal?';
  d['id']['rm.faq_2_a']='Kami mengambil pendekatan holistik yang melampaui kepatuhan administratif. Tim kami mengevaluasi proses operasional Anda, memetakan celah pengendalian, merancang mekanisme pengendalian yang disesuaikan, dan melakukan pengujian ketat untuk memastikan efektivitas dan keselarasan regulasi.';
  d['id']['rm.faq_3_q']='Dapatkah Chatura membantu dalam investigasi fraud dan analisis forensik?';
  d['id']['rm.faq_3_a']='Ya. Tim forensik kami melakukan investigasi menyeluruh terhadap dugaan fraud, pelanggaran keuangan, dan ketidakberesan. Kami memberikan temuan yang dapat ditindaklanjuti, laporan berbasis bukti, dan rekomendasi untuk memperkuat pertahanan anti-fraud Anda serta mendukung proses hukum jika diperlukan.';
  d['id']['rm.faq_4_q']='Industri mana saja yang dilayani oleh praktik manajemen risiko Chatura?';
  d['id']['rm.faq_4_a']='Kami melayani berbagai industri termasuk Layanan Keuangan, Manufaktur, Teknologi, Energi & Sumber Daya, Kesehatan, dan Pemerintah & Badan Usaha Milik Negara (BUMN). Pengalaman lintas sektor kami memungkinkan kami menyesuaikan kerangka risiko dengan konteks regulasi dan operasional tertentu.';
  d['id']['rm.hero_label']='Manajemen Risiko';
  d['id']['rm.hero_title_1']='Membangun Ketahanan';
  d['id']['rm.hero_title_green']='Melalui Intelijen Risiko';
  d['id']['rm.hero_title_2']='yang Proaktif';
  d['id']['rm.hero_desc']='Kami mengidentifikasi, menilai, dan mengelola risiko bisnis untuk membangun ketahanan dan mendukung pertumbuhan yang berkelanjutan serta percaya diri.';
